mapper.select:
SELECT cp.*,
       u.name AS user_name
  FROM community_post cp
  JOIN users u ON cp.user_id = u.id
 WHERE cp.status = #{status}
   AND cp.created_at >= #{since}
 ORDER BY (cp.like_count * 3 + cp.view_count + cp.comment_count * 2) DESC
 LIMIT #{limit}

